INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('diplomatic-d3cf880d-moex-00014', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-114-10317cea', 'sub-diplomatic-d3cf880d-02', NULL, 'single_choice', '關於｢國際法｣與「國內法」的關係，下列敘述何者錯誤？', '["就理論上而言，國際法與國內法的關係通常指向「一元論」及「二元論」二種不同的方法取徑", "我國憲法第141條規定：「中華民國之外交，應……尊重條約及聯合國憲章，……」", "一國得以國內法律或國內立法程序疏漏等理由，作為違反國際法上義務之正當理由", "一國國內法院能否直接適用國際法，很大程度取決於各該國家的憲法、法律規定及法院裁判"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:44+00:00", "source_pdf_sha1": "50baf7169a04", "answer_pdf_sha1": "f8981815935e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00015', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-114-10317cea', 'sub-diplomatic-d3cf880d-02', NULL, 'single_choice', '依據《維也納條約法公約》對於條約所作之定義，下列何者非為條約？', '["京都議定書", "斯德哥爾摩人類環境宣言", "維也納外交關係公約", "馬關條約"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:44+00:00", "source_pdf_sha1": "50baf7169a04", "answer_pdf_sha1": "f8981815935e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00016', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-114-10317cea', 'sub-diplomatic-d3cf880d-02', NULL, 'single_choice', 'Pactatertiisnecnocentnecprosunt一詞之意義為何？', '["條約神聖原則", "需經國家同意方能使條約生效", "條約僅對締約國生效，不對第三國產生義務", "情勢發生重大且不可預見之變化"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:44+00:00", "source_pdf_sha1": "50baf7169a04", "answer_pdf_sha1": "f8981815935e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00017', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-114-10317cea', 'sub-diplomatic-d3cf880d-02', NULL, 'single_choice', '關於「不干涉內政原則」，下列敘述何者錯誤？', '["國際法基本規則要求，一國沒有權利侵害其他國家對國內事務的管轄", "依《聯合國憲章》第7章所為的執行措施，得適用於一國國內管轄事件", "依《聯合國憲章》規定，聯合國原則上不得干涉一國國內管轄事件", "依《聯合國憲章》要求，會員國須將所有爭端依憲章提交國際法院解決"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:44+00:00", "source_pdf_sha1": "50baf7169a04", "answer_pdf_sha1": "f8981815935e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00018', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-114-10317cea', 'sub-diplomatic-d3cf880d-02', NULL, 'single_choice', '關於國際法上的「國家繼承」，下列敘述何者錯誤？', '["1978年《關於國家在條約方面的繼承的維也納公約》，與《維也納外交關係公約》相比，前者 之爭議性較大", "1978年《關於國家在條約方面的繼承的維也納公約》為國家繼承原則之法典化成果之一", "國際法委員會於1983年已通過《關於國家在財產、檔案及債務方面的繼承的維也納公約》，但 該公約尚未生效", "國家繼承包括因交戰關係而占領等暫時性的改變"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:44+00:00", "source_pdf_sha1": "50baf7169a04", "answer_pdf_sha1": "f8981815935e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00019', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-114-10317cea', 'sub-diplomatic-d3cf880d-02', NULL, 'single_choice', '關於「人權」，下列敘述何者正確？', '["《經濟社會文化權利國際公約》並沒有提到民族（人民）自決權", "《聯合國憲章》第1條規定，聯合國設立的目的是在達成國際合作，藉以促進和鼓勵對全體人 類之人權與基本自由的尊重", "《國際人權憲章》是《公民與政治權利國際公約》及《經濟社會文化權利國際公約》二者之總稱", "人權事務屬於一國的國內管轄範圍，不適用國際法規範"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:44+00:00", "source_pdf_sha1": "50baf7169a04", "answer_pdf_sha1": "f8981815935e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00020', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-114-10317cea', 'sub-diplomatic-d3cf880d-02', NULL, 'single_choice', '下列區域何者並未受多邊公約之規範？', '["國家管轄以外的海床和洋底及其底土", "南極", "地心", "蘇伊士運河"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:44+00:00", "source_pdf_sha1": "50baf7169a04", "answer_pdf_sha1": "f8981815935e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00021', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-114-10317cea', 'sub-diplomatic-d3cf880d-02', NULL, 'single_choice', '依據《聯合國海洋法公約》第39條，關於船舶與航空器「過境通行」之義務，下列敘述何者錯誤？', '["船舶與航空器應毫不遲延地通過或飛越海峽", "船舶與航空器不得對海峽沿岸國的主權、領土完整或政治獨立進行任何武力威脅或使用武力", "船舶與航空器除因不可抗力或遇難而有必要外，不得從事其繼續不停和迅速過境的通常方式所 附帶發生的活動以外的任何活動", "船舶與航空器得進行任何研究或測量活動"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:44+00:00", "source_pdf_sha1": "50baf7169a04", "answer_pdf_sha1": "f8981815935e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00022', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-114-10317cea', 'sub-diplomatic-d3cf880d-02', NULL, 'single_choice', '依據《聯合國海洋法公約》，關於群島水域，下列敘述何者錯誤？', '["群島國應尊重其他國家所鋪設的通過其水域而不靠岸的現有海底電纜", "群島國應承認直接相鄰國在群島水域範圍內某些區域的傳統捕魚權", "原則上所有國家的船舶均享有通過群島水域的無害通過權", "航空器不享有群島水域空中通行權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:44+00:00", "source_pdf_sha1": "50baf7169a04", "answer_pdf_sha1": "f8981815935e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00023', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-114-10317cea', 'sub-diplomatic-d3cf880d-02', NULL, 'single_choice', '有關世界貿易組織之爭端解決機構，下列敘述何者正確？', '["世界貿易組織爭端解決機構是國際貿易法領域中成立的第一個爭端解決機制", "《世界貿易組織協定》係爭端解決機構適用之唯一法源", "爭端解決機構就《世界貿易組織協定》之爭端，享有強制和專屬的管轄權", "爭端解決機構已獲得世界貿易組織會員之信任，向其上訴機構提出上訴的比率相當低"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:44+00:00", "source_pdf_sha1": "50baf7169a04", "answer_pdf_sha1": "f8981815935e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL)
